examples.code:
package main

import (
	"fmt"

	"github.com/malcolmston/matplotlib"
)

func main() {
	fig := matplotlib.NewFigure(400, 300)
	ax := fig.AddAxes()
	ax.Bar([]string{"a", "b", "c"}, []float64{3, 7, 2})
	ax.SetTitle("Counts")

	img := fig.RenderImage()
	fmt.Printf("%dx%d\n", img.Bounds().Dx(), img.Bounds().Dy())
}
